mapper.select:
SELECT COUNT(*)
FROM admin_inquiry
WHERE id = #{inquiryId}
  AND user_id = #{userId}

SELECT ai.no, ai.id, ai.user_id AS userId, u.name AS userName, u.nickname AS userNickname, ai.category, ai.title, ai.contact_name AS contactName, ai.contact_email AS contactEmail, ai.contact_phone AS contactPhone, ai.status, ai.created_at AS createdAt, ai.updated_at AS updatedAt, ai.closed_at AS closedAt, lm.content AS lastMessage, lm.created_at AS lastMessageAt FROM admin_inquiry ai JOIN users u ON u.id = ai.user_id LEFT JOIN ( SELECT m.inquiry_id, m.content, m.created_at FROM admin_inquiry_message m JOIN ( SELECT inquiry_id, MAX(no) AS max_no FROM admin_inquiry_message GROUP BY inquiry_id ) mm ON mm.max_no = m.no ) lm ON lm.inquiry_id = ai.id
ai.status = #{status}
AND ai.category = #{category}
AND ( ai.title LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR lm.content LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY ai.created_at DESC LIMIT 200
